130→window.onload = function () {
131→    /* If the WebView loads too early on Android <= 4.3 (which happens
132→       on the first card or regularly with WebView switching enabled),
133→       the window dimensions returned to us will be default built-in
134→       values. In this case, issuing a scroll event will force the
135→       browser to recalculate the dimensions and give us the correct
136→       values, so we do this every time. This lets us resize images
137→       correctly. */
138→    window.scrollTo(0, 0);
139→    resizeImages();
140→    window.location.href = "#answer";
