571→    /**
572→     * If the activity is [RESUMED], or is called from [onResume] then execute the pending
573→     * operations in [refreshRequired].
574→     *
575→     * If the activity is NOT [RESUMED], wait until [onResume]
576→     */
577→    @NeedsTest("if opExecuted is called while activity is in the background, audio plays onResume")
578→    private fun refreshIfRequired(isResuming: Boolean = false) {
579→        // Defer the execution of `opExecuted` until the user is looking at the screen.
580→        // This ensures that audio/timers are not accidentally started
581→        if (isResuming || lifecycle.currentState.isAtLeast(RESUMED)) {
582→            refreshRequired?.let {
583→                Timber.d("refreshIfRequired: redraw")
584→                // if changing code, re-evaluate `refreshRequired = null` in `updateCardAndRedraw`
585→                launchCatchingTask { updateCardAndRedraw() }
586→                refreshRequired = null
587→            }
588→        } else if (refreshRequired != null) {
589→            // onResume() will execute this method
590→            Timber.d("deferred refresh as activity was not STARTED")
591→        }
592→    }
